MERGE INTO CONSULTAS FIN USING (SELECT '800574LISTADOFUNCIONARIOSCPTO' INFORME ,TO_CLOB(q'[SELECT HISTORICOS.COMPANIA, HISTORICOS.ID_DE_PROCESO, HISTORICOS.ANO, HISTORICOS.MES, HISTORICOS.PERIODO,
HISTORICOS.ID_DE_EMPLEADO, PERSONAL.NOMBRECOMPLETO, HISTORICOS.ID_DE_CONCEPTO, HISTORICOS.VALOR
FROM HISTORICOS 
LEFT JOIN PERSONAL
ON PERSONAL.COMPANIA = HISTORICOS.COMPANIA
AND PERSONAL.ID_DE_EMPLEADO = HISTORICOS.ID_DE_EMPLEADO
WHERE HISTORICOS.COMPANIA = s$compania$s
AND HISTORICOS.ANO = s$ano$s
AND HISTORICOS.MES = s$mes$s
AND HISTORICOS.ID_DE_PROCESO = s$proceso$s
AND HISTORICOS.PERIODO = s$periodo$s
AND HISTORICOS.ID_De_CONCEPTO = s$concepto$s
AND HISTORICOS.ID_DE_EMPLEADO between (CASE WHEN s$empleado$s > 0 THEN  s$empleado$s   ELSE  '0' END) AND (CASE WHEN s$empleado$s > 0 THEN  s$empleado$s  ELSE '999999999'  END) ORDER BY HISTORICOS.ID_DE_EMPLEADO]') CONSULTA, 999 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);